	aiHiring: {
		"title": "Garna - AI Recruitment Platform",
		"description": "Skip the pre-screens. Hire proven talent instantly with AI-powered recruitment and verified candidate reports",
		"keywords": "AI recruitment, hire talent, AI hiring, candidate screening, Garna, recruitment platform",
		"ogImage": "https://cdn.prod.website-files.com/690b359fa4596a165b817850/691c82150090fae9b2280e93_Frame%201618873305.png",
		"htmlClass": "scroll-smooth",
		"bodyClass": "antialiased selection:bg-[#5EA500] selection:text-white overflow-x-hidden text-gray-300 bg-[#050505] z-10 relative",
		"iconLibrary": "iconify",
		"headExtra": "<style>\n        body {\n            font-family: 'Inter', sans-serif;\n            background-color: #050505;\n            color: #a1a1aa;\n        }\n\n        h1,\n        h2,\n        h3,\n        h4,\n        .font-heading {\n            font-family: 'Manrope', sans-serif;\n        }\n\n        /* Smooth scrolling */\n        html {\n            scroll-behavior: smooth;\n        }\n\n        /* Custom scrollbar */\n        ::-webkit-scrollbar {\n            width: 6px;\n        }\n\n        ::-webkit-scrollbar-track {\n            background: #050505;\n        }\n\n        ::-webkit-scrollbar-thumb {\n            background: #262626;\n            border-radius: 10px;\n        }\n\n        ::-webkit-scrollbar-thumb:hover {\n            background: #404040;\n        }\n\n        /* Glassmorphism utilities (match home page header/footer) */\n        .glass {\n            background: rgba(255, 255, 255, 0.03);\n            backdrop-filter: blur(12px);\n            -webkit-backdrop-filter: blur(12px);\n            border: 1px solid rgba(255, 255, 255, 0.08);\n        }\n\n        .glass-card {\n            background: rgba(255, 255, 255, 0.02);\n            backdrop-filter: blur(20px);\n            -webkit-backdrop-filter: blur(20px);\n            border: 1px solid rgba(255, 255, 255, 0.06);\n            box-shadow: 0 4px 30px rgba(0, 0, 0, 0.1);\n        }\n\n        .glass-high {\n            background: rgba(20, 20, 20, 0.6);\n            backdrop-filter: blur(16px);\n            -webkit-backdrop-filter: blur(16px);\n            border-bottom: 1px solid rgba(255, 255, 255, 0.08);\n        }\n\n        .glass-nav {\n            background: rgba(5, 5, 5, 0.7);\n            backdrop-filter: blur(16px);\n            -webkit-backdrop-filter: blur(16px);\n            border-bottom: 1px solid rgba(255, 255, 255, 0.08);\n        }\n\n        /* Grid Pattern Background */\n        .bg-grid {\n            background-image: linear-gradient(to right, rgba(255, 255, 255, 0.05) 1px, transparent 1px),\n                linear-gradient(to bottom, rgba(255, 255, 255, 0.05) 1px, transparent 1px);\n            background-size: 40px 40px;\n        }\n\n        /* Hide details marker */\n        details>summary {\n            list-style: none;\n        }\n\n        details>summary::-webkit-details-marker {\n            display: none;\n        }\n\n        /* Animations */\n        @keyframes float {\n            0% {\n                transform: translateY(0px);\n            }\n\n            50% {\n                transform: translateY(-10px);\n            }\n\n            100% {\n                transform: translateY(0px);\n            }\n        }\n\n        .animate-float {\n            animation: float 6s ease-in-out infinite;\n        }\n    </style>\n    <link id=\"all-fonts-link-font-manrope\" rel=\"stylesheet\"\n        href=\"https://fonts.googleapis.com/css2?family=Manrope:wght@300;400;500;600;700;800&amp;display=swap\">\n    <style id=\"all-fonts-style-font-manrope\">\n        .font-manrope {\n            font-family: 'Manrope', sans-serif !important;\n        }\n    </style>",	},
